import { useState, useEffect } from "react"
import React from "react"
import { useApi } from "./components/useApi"

// Define the Todo item type based on server schema
type TodoItem = {
  id: number | null
  name: string
  description?: string
  completed: boolean
}

function App() {
  const { data, loading, error, create, update, remove, refresh } = useApi<TodoItem>("items")

  const [inputValue, setInputValue] = useState("")

  useEffect(() => {
    // Load todos on mount
    loadTodos()
  }, [])

  const loadTodos = async () => {
    try {
      await api.get<TodoItem[]>("/api/items")
    } catch (e) {
      console.error("Failed to load todos:", e)
    }
  }

  const handleAddTodo = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault()
    if (!inputValue.trim()) return

    try {
      await api.post("/api/items", { name: inputValue, description: "" })
      await refreshTodos()
    } catch (e) {
      alert("Failed to add todo: " + e?.message || e?.toString())
    }
  }

  const handleToggleCompletion = async (id: number) => {
    try {
      await api.put(`/api/items/${id}`, { completed: !prevTodo.completed })
      await refreshTodos()
    } catch (e) {
      alert("Failed to update todo: " + e?.message || e?.toString())
    }
  }

  const handleDeleteTodo = async (id: number) => {
    if (!window.confirm("Are you sure you want to delete this todo?")) return
    try {
      await api.delete(`/api/items/${id}`)
      await refreshTodos()
    } catch (e) {
      alert("Failed to delete todo: " + e?.message || e?.toString())
    }
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white shadow py-6 px-4 sm:px-8">
        <div className="max-w-xl mx-auto flex justify-between items-center">
          <h1 className="text-3xl font-bold text-gray-900">📝 Todo List</h1>
          <button 
            onClick={loadTodos} 
            disabled={loading}
            className={`px-4 py-2 rounded-lg transition duration-150 ${loading ? 'bg-gray-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-md'} focus:ring-2 focus:ring-indigo-500 focus:ring-opacity-50`}
          >
            {loading ? "Loading..." : "Refresh"}
          </button>
        </div>
      </header>

      <main className="max-w-xl mx-auto p-4 sm:p-6">
        {error && (
          <div className="bg-red-100 border border-red-200 text-red-800 p-4 rounded-lg mb-6" role="alert">
            <strong className="mr-2">Error:</strong> {error}
          </div>
        )}

        {loading && (
          <div className="flex justify-center items-center min-h-[150px]">
            <svg className="animate-spin h-8 w-8 text-indigo-600 mr-2" viewBox="0 0 50 50">
              <circle cx="25" cy="25" r="24" fill="none" stroke="currentColor" strokeWidth="5" strokeDasharray="10 20" />
            </defs>
            <path d="M25 25A25 25 0 1 0 25 25L25 25Z" fill="none" stroke="currentColor" strokeWidth="5" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
            <p className="text-indigo-600">Loading todos...</p>
        )}

        {!data && !loading && (
          <div className="flex flex-col items-center justify-center py-12 bg-white rounded-xl shadow-lg border border-gray-100">
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="M6 12l6-6 6 6"/><path d="M18 12l-6 6-6-6"/></defs>
              <path d="M12 3v9M12 15h12m-12 4c0-1.6-.6-3-2-4V7c0-1.6-.6-3-2-4l-6 6L12 19v-6l6-6c1.6 0 3 .6 5 2v4c0 1.6-.6 3-2 4l-6-6L12 3z"/></svg>
            <h2 className="text-2xl font-semibold text-gray-900 mb-2">You're all caught up!</h2>
            <p className="text-gray-500 max-w-md mb-8">Looks like your to-do list is empty. Time to add some things!</p>
          </div>
        )}

        {/* Add Todo Form */}
        <form onSubmit={handleAddTodo} className="bg-white p-6 rounded-xl shadow-lg mb-10 border border-gray-100">
          <div className="flex flex-col gap-3 mb-4">
            <input
              type="text"
              placeholder="What do you need to get done?"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              className="w-full p-3 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition duration-150 placeholder:text-gray-400"
              required
            />
            <textarea
              rows={3}
              placeholder="Add more details or notes..."
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              className="w-full p-3 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-none placeholder:text-gray-400"
              required
            ></textarea>
          </div>
          <button 
            type="submit" 
            disabled={inputValue.trim() === ""}
            className={`w-full py-3 px-6 rounded-xl font-semibold transition duration-200 ${inputValue.trim() === "" ? 'bg-gray-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg focus:ring-4 focus:ring-indigo-500 focus:ring-opacity-50'} focus:outline-none focus:ring-2`}
          >
            {inputValue.trim() ? "Add New Todo" : "Please enter a task"}
          </button>
        </form>

        {data && data.length > 0 && (
          <div className="space-y-3">
            {data.map((todo) => (
              <div key={todo.id} className={`flex items-center justify-between p-4 rounded-xl transition duration-200 ${todo.completed ? 'bg-green-50 border-l-4 border-green-500' : 'bg-white hover:shadow-lg'} shadow-sm'>
                <input
                  type="checkbox"
                  checked={todo.completed}
                  onChange={() => handleToggleCompletion(todo.id)}
                  className="h-5 w-5 text-indigo-600 border-gray-300 rounded-md focus:ring-indigo-500 cursor-pointer"
                />
                <div className={`flex flex-col gap-1 ${todo.completed ? 'opacity-70' : ''}`}>
                    <p className={`text-lg ${todo.completed ? 'line-through text-gray-500' : 'text-gray-900'} font-medium`}>
                      {todo.name}
                    </p>
                    {todo.description && (
                        <p className={`text-sm ${todo.completed ? 'text-gray-400' : 'text-gray-600'}`}>
                          {todo.description}
                        </p>
                      )}
                    {!todo.description && !todo.completed && (
                        <span className="text-xs text-indigo-500">Optional description</span>
                      )}
                  </p>
                </div>
                <button 
                    onClick={() => handleDeleteTodo(todo.id)} 
                    className={`px-3 py-1.5 rounded-lg text-sm font-medium transition duration-200 ${todo.completed ? 'bg-gray-100 hover:bg-red-50' : 'bg-white text-red-600 hover:bg-red-50 hover:border-red-300'} border border-transparent focus:ring-2 focus:ring-red-500`}
                  >
                    Delete
                </button>
              </div>
            ))}
          </div>
        )}

        {/* Empty State */}
        {!data && !loading && (
          <div className="flex flex-col items-center justify-center py-16 bg-white rounded-2xl shadow-2xl border border-gray-50">
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="M6 12l6-6 6 6"/><path d="M18 12l-6 6-6-6"/></defs>
              <path d="M12 3v9m0 6h12m-12 4c0-1.6-.6-3-2-4V7c0-1.6-.6-3-2-4l-6 6L12 19v-6l6-6L12 3z"/></svg>
            <h2 className="text-3xl font-extrabold text-gray-900 mt-4">No Todos Yet</h2>
            <p className="text-gray-500 max-w-lg text-center mb-8">It looks like you don't have any tasks added. Let's get organized!</p>
            <button 
                onClick={handleAddTodo} 
                className="px-8 py-3 rounded-full bg-indigo-600 hover:bg-indigo-700 text-white shadow-xl focus:ring-4 focus:ring-indigo-500 focus:ring-opacity-50 transform hover:-translate-y-0.5 transition duration-300"
            >
              + Add New Todo
            </button>
          </div>
        )}
      </main>

      <footer className="bg-gray-900 py-6 px-4 sm:px-8">
        <div className="max-w-xl mx-auto text-center text-gray-500">
          &copy; {new Date().getFullYear()} Todo List. Built with Remix & SQLite.
        </div>
      </footer>
    </div>
  )
}

export default App
